// APIClient.swift
import Foundation

enum Endpoint {
    case production
    case legacy
    
    var url: URL {
        switch self {
        case .production:
            return URL(string: "https://api.example.com/data")!
        case .legacy:
            return URL(string: "http://legacy.internal/data")!
        }
    }
}

actor APIClient {
    static let shared = APIClient()
    
    func fetch(from endpoint: Endpoint) async -> String {
        var request = URLRequest(url: endpoint.url)
        request.httpMethod = "GET"
        
        do {
            let (data, _) = try await URLSession.shared.data(for: request)
            return String(data: data, encoding: .utf8) ?? "Invalid response"
        } catch {
            return "Request failed: \(error.localizedDescription)"
        }
    }
}